    ngx.say('{"error": "Empty request body"}')
    ngx.exit(ngx.HTTP_BAD_REQUEST)
end

-- Parse XML with entity expansion enabled
local function parse_xml(xml_string)
    local handler = xml.xmlParser()
    local parsed = handler:ParseXmlText(xml_string)
    return parsed
end

local success, parsed_xml = pcall(parse_xml, body)

if not success then
