-- Helper function to extract text from XML node
local function get_node_text(node)
    if type(node) == "string" then
        return node
    end
    if type(node) == "table" then
        for i, v in ipairs(node) do
            if type(v) == "string" then
                return v
            end
        end
    end
    return ""
end

-- Helper function to find node by tag name
local function find_node(root, tag_name)
    if type(root) ~= "table" then
        return nil
    end
    
    if root._name == tag_name then
        return root
    end
    
    for i, child in ipairs(root) do
        if type(child) == "table" then
            local found = find_node(child, tag_name)
            if found then
                return found
            end
        end
    end
    
    return nil
end

-- Helper function to get all nodes by tag name
local function find_all_nodes(root, tag_name, results)
    results = results or {}
    
    if type(root) ~= "table" then
        return results
    end
    
    if root._name == tag_name then
        table.insert(results, root)
    end
    
    for i, child in ipairs(root) do
        if type(child) == "table" then
            find_all_nodes(child, tag_name, results)
        end
    end
    
    return results
end

-- Extract SOAP envelope and body
local envelope = parsed_xml
local soap_body = find_node(envelope, "Body") or find_node(envelope, "soap:Body") or find_node(envelope, "SOAP-ENV:Body")

